def token_recall(a,b):
    # recall of tokens of b in a: common/len(b)
    ca=Counter(a.split())
    cb=Counter(b.split())
    common=0
    for tok in cb:
        common += min(cb[tok], ca.get(tok,0))
    if len(cb)==0: return 0.0
    return common/len(cb)

