def set_f1(a,b):
    sa=set(a.split())
    sb=set(b.split())
    inter = sa.intersection(sb)
    if not sa and not sb:
        return 1.0
    if not inter:
        return 0.0
    prec = len(inter)/len(sa)
    rec = len(inter)/len(sb)
    return 2*prec*rec/(prec+rec)

